import streamlit as st
import base64

st.set_page_config(
    page_title="실시간 물리 탑 쌓기 게임",
    page_icon="🧱",
    layout="centered"
)

st.title("🧱 마우스 드래그! 실시간 물리 탑 쌓기 게임")
st.markdown("""
이제 블록을 **마우스 움직임**으로 직접 제어할 수 있습니다! 
블록을 조준하고 클릭하면 중력을 받아 실시간으로 떨어지며, 중심을 잃고 비껴나가면 완전히 바닥으로 추락한 뒤 게임 오버를 시각적으로 연출합니다.
""")

if st.button("🔄 게임 새로 시작하기", type="primary"):
    st.rerun()

st.divider()

# 아래의 b64_game 변수는 코드 내에서 절대 줄바꿈을 하지 않는 완벽한 '한 줄' 문자열입니다.
b64_game = ""

# Base64 디코딩하여 완전무결한 웹 게임 프레임워크 복원
game_html = base64.b64decode(b64_game).decode('utf-8')

# 화면에 안전하게 렌더링
st.components.v1.html(game_html, height=580)
